/// clear BSS segment
pub fn clear_bss() {
    extern "C" {
        fn sbss();
        fn ebss();
    }
    (sbss as usize..ebss as usize).for_each(|a| unsafe { (a as *mut u8).write_volatile(0) });
}

pub fn layout() {
    extern "C" {
        fn stext(); // begin addr of text segment
        fn etext(); // end addr of text segment
        fn srodata(); // start addr of Read-Only data segment
        fn erodata(); // end addr of Read-Only data ssegment
        fn sdata(); // start addr of data segment
        fn edata(); // end addr of data segment
        fn sbss(); // start addr of BSS segment
        fn ebss(); // end addr of BSS segment
        fn boot_stack_lower(); // stack lower bound
        fn boot_stack_top(); // stack top
    }
    trace!(
        "[kernel] .text [{:#x}, {:#x})",
        stext as usize,
        etext as usize
    );
    trace!(
        "[kernel] .rodata [{:#x}, {:#x})",
        srodata as usize, erodata as usize
    );
    trace!(
        "[kernel] .data [{:#x}, {:#x})",
        sdata as usize, edata as usize
    );
    trace!(
        "[kernel] boot_stack bottom={:#x}, top={:#x}",
        boot_stack_top as usize, boot_stack_lower as usize
    );
    trace!("[kernel] .bss [{:#x}, {:#x})", sbss as usize, ebss as usize);
}

static FISRT_HART: AtomicBool = AtomicBool::new(true);

/// the rust entry-point of os
#[no_mangle]
pub fn rust_main() {
    if FISRT_HART.compare_exchange(true, false, core::sync::atomic::Ordering::SeqCst, core::sync::atomic::Ordering::SeqCst)
        .is_ok() {
            clear_bss();
            logging::init();
            layout();
            hart::cpu::init();
            mm::init();
            process::trap::init_stvec();
            driver::init_block_device();
            // block_device_test();
            // unsafe {
            //     sstatus::set_sum();
            // }
            fs::init();
            process::init_origin_task();
            cpu::run_task();
            #[cfg(feature = "multi_hart")]
            hart::cpu::start_other_hart();
            // // 暂时放在这里，如果没有它，之后就会触发内核中断,因为离开rust_main函数之后，pc会跑到0的位置。
            loop {}

        } else {
            hart::cpu::init();    
            loop {}
        }


    // Warning: 这里我们自己自动的让qemu终止!
    // QEMU_EXIT_HANDLE.exit_success();
}

OUTPUT_ARCH(riscv)
ENTRY(_start)
/* BASE_ADDRESS = 0x80200000; */
BASE_ADDRESS = 0xffffffff80200000;

SECTIONS
{
    . = BASE_ADDRESS;
    skernel = .;

    stext = .;
    .text : {
        *(.text.entry)
        *(.text .text.*)
    }

    . = ALIGN(4K);
    etext = .;
    srodata = .;
    .rodata : {
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
    }

    . = ALIGN(4K);
    erodata = .;
    sdata = .;
    .data : {
        *(.data .data.*)
        *(.sdata .sdata.*)
    }

    . = ALIGN(4K);
    edata = .;
    sstack = .;
    .stack : {
        *(.bss.stack)
    }
    . = ALIGN(4K);
    estack = .;
    .bss : {
        sbss = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
    }

    . = ALIGN(4K);
    ebss = .;
    ekernel = .;

    /DISCARD/ : {
        *(.eh_frame)
    }
}

