//! 地址转换函数

/*
    1. 虚拟地址和物理地址之间的转换
    2. 页号和地址之间的转换
    3. align相关的函数，etc...
    4. 解引用物理地址直接得到值 (mut 和 不可变)（T 和 byte）
*/

use crate::config::mm::{LOW_LIMIT, PADDR_HIGH, PADDR_LOW, PAGE_SIZE, PAGE_SIZE_BITS, PHY_TO_VIRT_OFFSET, SV39_VPN_1, SV39_VPN_2, SV39_VPN_3, USER_UPPER_LIMIT, VADDR_HIGH, VADDR_LOW, VIRTIO0};

use super::page_table::PageTableEntry;

pub type VirtAddr = usize;
pub type PhysAddr = usize;

pub fn vaddr_is_align(vaddr: VirtAddr) -> bool {
    (vaddr & (PAGE_SIZE - 1)) == 0
}

pub fn check_kernel_va(vaddr: VirtAddr) {
    assert!((VADDR_LOW <= vaddr && vaddr <= VADDR_HIGH) || 
        (VIRTIO0 <= vaddr && vaddr <= VIRTIO0 + 0x4000));
}

pub fn check_user_va(vaddr: VirtAddr) {
    assert!((VADDR_LOW <= vaddr && vaddr <= VADDR_HIGH) || 
    (VIRTIO0 <= vaddr && vaddr <= VIRTIO0 + 0x4000) ||
    ((LOW_LIMIT <= vaddr && vaddr <= USER_UPPER_LIMIT))
    );
}

/// 默认了 paddr 在 低32位 仅限内核地址空间
#[allow(unused)]
pub fn phys_to_virt(paddr: PhysAddr) -> VirtAddr {
    assert!(PADDR_LOW <= paddr && paddr <= PADDR_HIGH);
    paddr | PHY_TO_VIRT_OFFSET
}

/// 物理地址 ---> 物理页号
pub fn phys_to_ppn(paddr: PhysAddr) -> usize {
    assert!(PADDR_LOW <= paddr && paddr <= PADDR_HIGH);
    paddr >> PAGE_SIZE_BITS
}

/// 物理地址 ---> 下一个物理页号
pub fn phys_to_ppn_next(paddr: PhysAddr) -> usize {
    assert!(PADDR_LOW <= paddr && paddr <= PADDR_HIGH);
    ( paddr >> PAGE_SIZE_BITS ) + 1
}

/// 虚拟地址转为物理地址 仅限内核地址空间
pub fn virt_to_phys(vaddr: VirtAddr) -> PhysAddr {
    check_kernel_va(vaddr);
    vaddr - PHY_TO_VIRT_OFFSET
}

/// 虚拟地址转页号 (页首)
pub fn virt_to_vpn(vaddr: VirtAddr) -> usize {
    check_user_va(vaddr);
    vaddr >> PAGE_SIZE_BITS
}

/// 虚拟地址转下一页的页号
pub fn virt_to_next_vpn(vaddr: VirtAddr) -> usize {
    check_user_va(vaddr);
    (vaddr >> PAGE_SIZE_BITS) + 1
}

/// 虚拟地址所在页的页首地址
pub fn align_down(vaddr: VirtAddr) -> VirtAddr {
    check_user_va(vaddr);
    vaddr & !(PAGE_SIZE - 1)
}

/// 虚拟地址 页首则保持为页首位置，页中值则为下一页的页首位置
pub fn align_up(vaddr: VirtAddr) -> VirtAddr {
    check_user_va(vaddr);
    (vaddr + PAGE_SIZE - 1) & !(PAGE_SIZE - 1)
}

/// 虚拟页号 --> 虚拟地址
pub fn vpn_to_virt(vpn: usize) -> VirtAddr {
    // assert!(VADDR_LOW <= (vpn << PAGE_SIZE_BITS) 
    //     && (vpn << PAGE_SIZE_BITS) <= VADDR_HIGH);
    check_user_va(vpn << PAGE_SIZE_BITS);
    vpn << PAGE_SIZE_BITS
}

/// 物理页号 ---> 物理地址
pub fn ppn_to_phys(ppn: usize) -> PhysAddr {
    ppn << PAGE_SIZE_BITS
}

/// 地址 -> 页内偏移 offset
pub fn vaddr_offset(vaddr: VirtAddr) -> usize {
    check_user_va(vaddr);
    vaddr & (PAGE_SIZE - 1)
}

/// 用户地址空间中 虚拟地址查询物理地址 pte的三级 (vpn2 vpn1 vpn0)
pub fn vaddr_to_pte_vpn(vaddr: VirtAddr) -> (usize, usize, usize) {
    check_user_va(vaddr);
    (
        (vaddr >> SV39_VPN_3) & 0x1ff,
        (vaddr >> SV39_VPN_2) & 0x1ff,
        (vaddr >> SV39_VPN_1) & 0x1ff
    )
}

/// 此处的物理地址，由于在内核中不能直接访问，所以需要将其转换为虚拟地址。
/// 一般情况下，无法从pa转换为va,但是内核地址空间是我们人为的映射过去的，所以这个offset已经确定了。
/// 于是就可以转换。但是仅限内核地址空间使用，用户地址空间无法使用这个函数！
/// 直接从物理地址 解引用获得pte array  4k的页面有512个usize
pub fn pte_array(paddr: PhysAddr) -> &'static mut [PageTableEntry] {
    assert!(PADDR_LOW <= paddr && paddr <= PADDR_HIGH);
    unsafe {
        core::slice::from_raw_parts_mut(phys_to_virt(paddr) as *mut PageTableEntry, 512)
    }
}

/// 从物理地址 解引用获得byte array
pub fn byte_array(paddr: PhysAddr) -> &'static mut [u8] {
    assert!(PADDR_LOW <= paddr && paddr <= PADDR_HIGH);
    unsafe {
        core::slice::from_raw_parts_mut(phys_to_virt(paddr) as *mut u8, PAGE_SIZE)
    }
}

/// 从物理地址 解引用获得结构体 T immutable
pub fn get_ref<T>(paddr: PhysAddr) -> &'static T {
    assert!(PADDR_LOW <= paddr && paddr <= PADDR_HIGH);
    unsafe {
        (phys_to_virt(paddr) as *const T).as_ref().unwrap()
    }
}
/// 从物理地址 解引用获得结构体 T mutable
pub fn get_mut<T>(paddr: PhysAddr) -> &'static mut T {
    assert!(PADDR_LOW <= paddr && paddr <= PADDR_HIGH);
    unsafe {
        (phys_to_virt(paddr) as *mut T).as_mut().unwrap()
    }
}

#[allow(unused)]
pub fn address_test() {
    log::info!("[test]: Start address test");
    use crate::mm::address::*;
    let va = 0xffff_ffff_8065_4321usize;
    let vpn = 0xffff_ffff_8065_4usize;
    let nxt_vpn = 0xffff_ffff_8065_5usize;
    let align_d = 0xffff_ffff_8065_4000usize;
    let align_u = 0xffff_ffff_8065_5000usize;
    let va_off = 0x321usize;
    let pa = 0x8065_4321usize;
    let ppn = 0x8065_4usize;
    let nxt_ppn = 0x8065_5usize;
    assert_eq!(phys_to_virt(pa), va);
    assert_eq!(phys_to_ppn(pa), ppn);
    assert_eq!(phys_to_ppn_next(pa), nxt_ppn);
    assert_eq!(virt_to_phys(va), pa);
    assert_eq!(virt_to_vpn(va), vpn);
    assert_eq!(virt_to_next_vpn(va), nxt_vpn);
    assert_eq!(align_down(va), align_d);
    assert_eq!(align_up(va), align_u);
    assert_eq!(vpn_to_virt(vpn), align_d);
    assert_eq!(ppn_to_phys(ppn), 0x8065_4000);
    assert_eq!(vaddr_offset(va), va_off);
    let (va1, va2, va3) = vaddr_to_pte_vpn(va);
    println!("{}, {}, {}", va1, va2, va3);
    log::info!("[test]: Address_test passed!");
}

//！ sv39 三级页表

/*
    1. 页表项 pte 中的各个位有关函数
    2. page_table 有 root_paddr 和 Frames
    3. 页表的函数
        1） activate 切换页表
        2） 找页表项 find_pte 和 find_pte_create
        3） map 和 unmap 可以有单次和多次映射之分
        4） 可以将虚拟地址翻译为物理地址
        5） 页表的token
*/

use core::{arch::asm, fmt::Debug};
use alloc::vec::Vec;
use alloc::vec;
use log::{debug, info};
use riscv::{addr::BitField, register::satp};

use crate::config::mm::{KERNEL_MMIO_PTE_POS, KERNEL_PTE_POS};

use super::{
    address::{phys_to_ppn, ppn_to_phys, pte_array, vaddr_offset, vaddr_to_pte_vpn, virt_to_vpn, vpn_to_virt, PhysAddr, VirtAddr}, 
    allocator::frame::{alloc_frame, FrameTracker}, 
    memory_set::mem_set::KERNEL_SPACE, 
    type_cast::PTEFlags,
};

#[derive(Clone, Copy)]
#[repr(C)]
pub struct PageTableEntry {
    pub pte: usize,
}

impl Debug for PageTableEntry {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        f.write_fmt(format_args!("PageTableEntry is ppn2: 0x{:x}, ppn1: 0x{:x}, ppn0: 0x{:x}, flags: {:?}",
            (self.pte >> 28 & 0x1ff), (self.pte >> 19 & 0x1ff), (self.pte >> 10 & 0x1ff),
            PTEFlags::from_bits((self.pte & 0x1ff) as u16).unwrap()
    ))
    }
}

/// pte中不同位的操作 设置位、判断位、初始化
impl PageTableEntry {
    ///
    pub fn new(ppn: usize, flags: PTEFlags) -> Self {
        PageTableEntry {
            pte: (ppn << 10) | (flags.bits() as usize)
        }
    }

    /// 
    pub fn empty() -> Self {
        PageTableEntry { pte: 0 }
    }

    ///
    pub fn flags(&self) -> PTEFlags {
        PTEFlags::from_bits((self.pte & ((1 << 9) - 1)) as u16).unwrap()
    }

    ///
    pub fn ppn(&self) -> usize {
        self.pte >> 10 & ((1usize << 44) - 1)
    }

    ///
    pub fn is_valid(&self) -> bool {
        self.flags().contains(PTEFlags::V)
    }

    ///
    pub fn is_writable(&self) -> bool {
        self.flags().contains(PTEFlags::W)
    }

    ///
    pub fn is_readable(&self) -> bool {
        self.flags().contains(PTEFlags::R)
    }

    ///
    pub fn is_executable(&self) -> bool {
        self.flags().contains(PTEFlags::X)
    }

    ///
    pub fn is_user(&self) -> bool {
        self.flags().contains(PTEFlags::U)
    }

    /// Unsafe：这里要确保flags是一个合法的PTEFlags
    pub fn set_flags(&mut self, flags: PTEFlags) {
        let new_flags = flags.bits() as usize;
        self.pte = (self.ppn() << 10 ) | new_flags;
    }
}

pub struct PageTable {
    root_paddr: usize,
    frames: Vec<FrameTracker>
}

impl PageTable {
    /// 页表的初始化
    pub fn new() -> Self {
        let frame = alloc_frame().unwrap();
        PageTable {
            root_paddr: ppn_to_phys(frame.ppn),
            frames: vec![frame]
        }
    }

    /// 需要一个全局变量KERNEL 然后要做映射
    pub fn new_user() -> Self {
        let frame = alloc_frame().unwrap();
        let kernel_root_paddr = unsafe {
            KERNEL_SPACE
                .as_ref()
                .unwrap()
                .pt
                .get()
                .as_ref()
                .unwrap()
                .root_paddr()
        };
        let user_pte_array = pte_array(ppn_to_phys(frame.ppn));
        let kernel_pte_array = pte_array(kernel_root_paddr);
        // Unsafe: 如果之后添加相关的地址空间时，需要对此处的pte进行修改，否则用户程序可能会丢失内核部分的地址空间区域。
        // 或许可以更加精细化一些! 因为我这里映射的空间远小于pte表对应的地址空间大小。
        (*user_pte_array)[KERNEL_PTE_POS] = (*kernel_pte_array)[KERNEL_PTE_POS];
        (*user_pte_array)[KERNEL_MMIO_PTE_POS] = (*kernel_pte_array)[KERNEL_MMIO_PTE_POS];
        PageTable { root_paddr: ppn_to_phys(frame.ppn), frames: vec![frame] }
    }

    pub fn root_ppn(&self) -> usize {
        phys_to_ppn(self.root_paddr)
    }

    pub fn root_paddr(&self) -> usize {
        self.root_paddr
    }

    /// page table token
    pub fn token(&self) -> usize {
        8usize << 60 | self.root_ppn()
    }

    /// activate page_table
    pub fn activate(&self) {
        // TODO: 不知道有没有逻辑问题？ DONE: 有时候我就是想刷本进程的页表！而不是切换页表！
        // TODO：这样子做是必要的吗？
        // let old_satp = satp::read().ppn();
        // if old_satp != self.root_ppn() {
        let satp = self.token();
        unsafe {
            satp::write(satp);
            asm!("sfence.vma");
        }
        // }
    }

    /// 找页表项 如果没有则创建一个 返回物理页号
    pub fn find_pte_create(&mut self, vaddr: VirtAddr) -> &mut PageTableEntry {
        let idx: (usize, usize, usize) = vaddr_to_pte_vpn(vaddr);
        let idx_array: [usize; 3] = [idx.0, idx.1, idx.2];
        let mut pa = self.root_paddr;
        for i in 0..3 {
            let pte = &mut pte_array(pa)[idx_array[i]];
            if i == 2 {
                return pte;
            }
            if !pte.is_valid() {
                let frame = alloc_frame().unwrap();
                *pte = PageTableEntry::new(frame.ppn, PTEFlags::V);
                self.frames.push(frame);        
            }
            pa = ppn_to_phys(pte.ppn());
        }
        unreachable!();
    }
    // 找页表项 如果没有，则返回None
    pub fn find_pte(&self, vaddr: VirtAddr) -> Option<&mut PageTableEntry> {
        let idx: (usize, usize, usize) = vaddr_to_pte_vpn(vaddr);
        let idx_array: [usize; 3] = [idx.0, idx.1, idx.2];
        let mut pa = self.root_paddr;
        for i in 0..3 {
            let pte = &mut pte_array(pa)[idx_array[i]];
            if !pte.is_valid() {
                return None;      
            }
            if i == 2 {
                return Some(pte);
            }

            pa = ppn_to_phys(pte.ppn());
        }
        unreachable!();
    }

    /// 映射一次虚拟页号和物理页号 同时要有flags
    pub fn map_one(&mut self, vpn: usize, ppn: usize, flags: PTEFlags) {
        let pte = self.find_pte_create(vpn_to_virt(vpn));
        if pte.is_valid() {
            info!("The vpn 0x{:x}, ppn 0x{:x}, pte: {:#?}", vpn, ppn, pte);
            panic!("The corresponding pte is valid.");
        }
        *pte = PageTableEntry::new(ppn, flags | PTEFlags::A | PTEFlags::D | PTEFlags::V);
    }

    /// 解除映射
    pub fn unmap(&self, vpn: usize) {
        if let Some(pte) = self.find_pte(vpn_to_virt(vpn)) {
            assert!(pte.is_valid(), "vpn {:?} is invalid before unmap", vpn);
            *pte = PageTableEntry::empty();
        } else {
            debug!("No pte of vpn {:#x}", vpn);
        }
    }

    /// 由vpn查找pte
    pub fn translate_vpn_to_pte(&self, vpn: usize) -> Option<PageTableEntry> {
        if let Some(pte) = self.find_pte(vpn_to_virt(vpn)) {
            Some(*pte)
        } else {
            None
        }
    }

    /// 由va查找pa
    pub fn translate_va_to_pa(&self, vaddr: VirtAddr) -> Option<PhysAddr> {
        let vpn = virt_to_vpn(vaddr);
        let offset = vaddr_offset(vaddr);
        if let Some(pte) = self.translate_vpn_to_pte(vpn) {
            assert!(pte.is_valid());
            Some(ppn_to_phys(pte.ppn()) + offset)
        } else {
            panic!("The va is not mapped! No pte");
        }
    }

    pub fn modify_flags(&self, vpn: usize, flags: PTEFlags) {
        let mut pte = self.translate_vpn_to_pte(vpn).unwrap();
        // 只需要修改UXWR四位
        for i in 1..=4 {
            pte.pte.set_bit(i,flags.bits().get_bit(i));
        }
    }

}

