                    debug_assert!(pte_flags.flags().contains(PTEFlags::COW));
                    debug_assert!(!pte_flags.flags().contains(PTEFlags::W));
                });
        }

        self.page_manager = SyncUnsafeCell::new(page_manager);
        self.handler = another.handler.clone();
    }

