// https://man7.org/linux/man-pages/man3/timespec.3type.html
/*
秒（Second）：通常用 s 表示，是国际标准的时间单位。
毫秒（Millisecond）：1 毫秒等于 0.001 秒，通常用 ms 表示。
微秒（Microsecond）：1 微秒等于 0.000001 秒，通常用 μs 表示，也可以用 us 表示。
纳秒（Nanosecond）：1 纳秒等于 0.000000001 秒，通常用 ns 表示。 */

#[derive(Clone, Copy, Default, Debug)]
pub struct TimeSpec {
    pub tv_sec: usize, /* 秒 */
    pub tv_nsec: usize, /*Nanoseconds 0 ~ 999'999'999 */
}

impl TimeSpec {
    pub fn new() -> TimeSpec {
        let current_time = current_time_ms();
        Self {
            tv_sec: current_time / 1000,
            tv_nsec: current_time_ns(),
        }
    }

    pub fn update(&mut self) {
        self.tv_sec =  current_time_ms() / 1000;
        self.tv_nsec = current_time_ns();
    }

    pub fn msec(self) -> usize {
        self.tv_nsec / NSEC_PER_MSEC + self.tv_sec * MSEC_PER_SEC
    }

    pub fn sec(&self) -> usize {
        self.tv_sec + self.tv_nsec / NSEC_PER_SEC
    }
}

// https://man7.org/linux/man-pages/man2/open.2.html
bitflags! {
    #[derive(Clone, Debug, PartialEq, Copy)]
    pub struct OpenFlags: u32 {
        // 只读模式
        const O_RDONLY = 0;
        // 只写模式
        const O_WRONLY = 1 << 0;
        // 读写模式
        const O_RDWR = 1 << 1;
        // 如果文件不存在，则创建文件
        const O_CREAT = 1 << 6;
        // 与 O_CREAT 一起使用，确保一定要创建文件。如果文件已经存在，则打开失败。即使是符号链接，也会失败。
        const O_EXCL = 1 << 7;
        // 如果文件存在，并且以写方式打开，则将文件截断为零长度
        const O_TRUNC = 1 << 9;
        // 在写入文件时始终追加到文件末尾
        const O_APPEND = 1 << 10;
        // 非阻塞模式
        const O_NONBLOCK = 1 << 11;
        // 同步写模式，要求每次写操作都同步到存储介质上
        const O_SYNC = 1 << 12;
        // 如果pathname不是目录，则打开失败
        const O_DIRECTORY = 1 << 16;

        const O_NOFOLLOW = 1 << 17;
        const O_CLOEXEC = 1 << 19;
        const O_NOATIME = 0x40000;
        const O_PATH = 0x200000;
    }
}

impl OpenFlags {
    pub fn is_writable(&self) -> bool {
        self.contains(Self::O_WRONLY) || self.contains(Self::O_RDWR)
    }

    pub fn is_readable(&self) -> bool {
        self.contains(Self::O_RDONLY) || self.contains(Self::O_RDWR)
    }
}

bitflags! {
    // TODO: 不确定，要根据具体的情况来设计。
    // 由 openat系统调用决定！
    pub struct FileMode: u8 {
        const FMODE_READ = 1 << 0;
        const FMODE_WRITE = 1 << 1;
    }
}

impl From<OpenFlags> for FileMode {
    fn from(value: OpenFlags) -> Self {
        let mut mode = FileMode::empty();
        match value {
            OpenFlags::O_RDONLY => mode.insert(FileMode::FMODE_READ),
            OpenFlags::O_WRONLY => mode.insert(FileMode::FMODE_WRITE),
            OpenFlags::O_RDWR => mode.insert(FileMode::FMODE_READ | FileMode::FMODE_WRITE),
            _ => {}
        }
        mode
    }
}

use bitmap_allocator::{BitAlloc, BitAlloc4K};

use crate::{config::task::MAX_PID, sync::SpinLock};

type PidAllocatorImpl = BitAlloc4K;

trait PidAllocator {
    fn init(&mut self);
    fn alloc_pid(&mut self) -> Option<Pid>;
    fn dealloc_pid(&mut self, pid: usize);
}

impl PidAllocator for PidAllocatorImpl {
    // The root pid = 1
    fn init(&mut self) {
        self.insert(2..MAX_PID);
    }

    fn dealloc_pid(&mut self, pid: usize) {
        self.dealloc(pid)
    }

    fn alloc_pid(&mut self) -> Option<Pid> {
        Some(Pid::init(self.alloc()?))
    }
}

pub static PID_ALLOCATOR: SpinLock<PidAllocatorImpl> = SpinLock::new(PidAllocatorImpl::DEFAULT);

pub struct Pid {
    pub value: usize,
}

impl Pid {
    pub fn init(value: usize) -> Self {
        Self { value }
    }
}

impl Drop for Pid {
    fn drop(&mut self) {
        dealloc_pid(self.value)
    }
}

pub fn init_pid_allocator() {
    PID_ALLOCATOR.lock().init();
}

pub fn alloc_pid() -> Option<Pid> {
    PID_ALLOCATOR.lock().alloc_pid()
}

pub fn dealloc_pid(pid: usize) {
    PID_ALLOCATOR.lock().dealloc(pid)
}

//！ 每个核中的环境信息

use core::arch::asm;

use riscv::register::sstatus;

use super::cpu::{get_cpu_id, get_cpu_local};

pub struct Env {
    sum_status: usize,
}

impl Env {
    pub const fn empty() -> Self {
        Self {
            sum_status: 0,
        }
    }

    pub fn sum_on(&mut self) {
        if self.sum_status == 0 {
            unsafe {
                sstatus::set_sum();
            }
        } else if !self.read_sum() {
            // 有时候在切换任务的时候，会发生系统调用还没运行结束，结果sum位就被硬件磨除了；
            self.sum_status = 0;
            unsafe {
                sstatus::set_sum();
            }
        }
        self.sum_status += 1;
    }

    pub fn sum_off(&mut self) {
        if self.sum_status == 1 {
            unsafe {
                sstatus::clear_sum();
            }
        }
        self.sum_status -= 1;
    }

    fn read_sum(&self) -> bool {
        let sstatus: usize;
        unsafe {
            asm!("csrr {}, sstatus", out(reg) sstatus);
        }
        (sstatus & (1 << 18)) == 1
    }
}

pub struct SumGuard {}

impl SumGuard {
    pub fn new() -> Self {
        let cpu_id = get_cpu_id();
        get_cpu_local(cpu_id).env.lock().sum_on();
        Self {}
    }
}

impl Drop for SumGuard {
    fn drop(&mut self) {
        let cpu_id = get_cpu_id();
        get_cpu_local(cpu_id).env.lock().sum_off();
    }
}
